import requests
import json
import sys
import time
from typing import Optional


class KongAdminClient:
    """Client for configuring Kong API Gateway via its Admin API."""

    def __init__(self, admin_url: str = "http://localhost:8001", timeout: int = 30):
        self.admin_url = admin_url.rstrip("/")
        self.timeout = timeout
        self.session = requests.Session()
        self.session.headers.update({
            "Content-Type": "application/json",
            "Accept": "application/json",
        })

    def _request(self, method: str, endpoint: str, data: Optional[dict] = None) -> dict:
        url = f"{self.admin_url}{endpoint}"
        try:
            response = self.session.request(
                method=method,
                url=url,
                json=data,
                timeout=self.timeout,
            )
            if response.status_code == 409:
                print(f"  [WARN] Resource already exists at {endpoint}")
                return response.json() if response.text else {}
            response.raise_for_status()
            return response.json() if response.text else {}
        except requests.exceptions.ConnectionError:
            print(f"[ERROR] Cannot connect to Kong Admin API at {self.admin_url}")
            raise
        except requests.exceptions.HTTPError as e:
            print(f"[ERROR] HTTP {e.response.status_code} for {method} {url}")
            print(f"  Response: {e.response.text}")
            raise

    def health_check(self) -> bool:
        try:
            response = self.session.get(f"{self.admin_url}/status", timeout=5)
            response.raise_for_status()
            status = response.json()
            print(f"[OK] Kong is running. Database reachable: {status.get('database', {}).get('reachable', 'unknown')}")
            return True
        except Exception as e:
            print(f"[ERROR] Kong health check failed: {e}")
            return False

    # --- Upstreams ---

    def create_upstream(self, name: str, algorithm: str = "round-robin",
                        hash_on: str = "none", healthchecks: Optional[dict] = None) -> dict:
        print(f"Creating upstream: {name}")
        payload = {
            "name": name,
            "algorithm": algorithm,
            "hash_on": hash_on,
        }
        if healthchecks:
            payload["healthchecks"] = healthchecks
        result = self._request("POST", "/upstreams", payload)
        print(f"  [OK] Upstream '{name}' created (id: {result.get('id', 'N/A')})")
        return result

    def add_target(self, upstream_name: str, target: str, weight: int = 100,
                   tags: Optional[list] = None) -> dict:
        print(f"  Adding target {target} (weight={weight}) to upstream '{upstream_name}'")
        payload = {
            "target": target,
            "weight": weight,
        }
        if tags:
            payload["tags"] = tags
        result = self._request("POST", f"/upstreams/{upstream_name}/targets", payload)
        print(f"    [OK] Target '{target}' added (id: {result.get('id', 'N/A')})")
        return result

    def list_upstreams(self) -> list:
        result = self._request("GET", "/upstreams")
        return result.get("data", [])

    def delete_upstream(self, name_or_id: str) -> dict:
        print(f"Deleting upstream: {name_or_id}")
        return self._request("DELETE", f"/upstreams/{name_or_id}")

    # --- Services ---

    def create_service(self, name: str, url: Optional[str] = None,
                       host: Optional[str] = None, port: int = 80,
                       protocol: str = "http", path: Optional[str] = None,
                       retries: int = 5, connect_timeout: int = 60000,
                       write_timeout: int = 60000, read_timeout: int = 60000,
                       tags: Optional[list] = None) -> dict:
        print(f"Creating service: {name}")
        payload = {
            "name": name,
            "retries": retries,
            "connect_timeout": connect_timeout,
            "write_timeout": write_timeout,
            "read_timeout": read_timeout,
        }
        if url:
            payload["url"] = url
        else:
            payload["host"] = host
            payload["port"] = port
            payload["protocol"] = protocol
            if path:
                payload["path"] = path
        if tags:
            payload["tags"] = tags

        result = self._request("POST", "/services", payload)
        print(f"  [OK] Service '{name}' created (id: {result.get('id', 'N/A')})")
        return result

    def get_service(self, name_or_id: str) -> dict:
        return self._request("GET", f"/services/{name_or_id}")

    def update_service(self, name_or_id: str, **kwargs) -> dict:
        print(f"Updating service: {name_or_id}")
        result = self._request("PATCH", f"/services/{name_or_id}", kwargs)
        print(f"  [OK] Service '{name_or_id}' updated")
        return result

    def delete_service(self, name_or_id: str) -> dict:
        print(f"Deleting service: {name_or_id}")
        return self._request("DELETE", f"/services/{name_or_id}")

    def list_services(self) -> list:
        result = self._request("GET", "/services")
        return result.get("data", [])

    # --- Routes ---

    def create_route(self, service_name_or_id: str, name: Optional[str] = None,
                     paths: Optional[list] = None, hosts: Optional[list] = None,
                     methods: Optional[list] = None, protocols: Optional[list] = None,
                     strip_path: bool = True, preserve_host: bool = False,
                     headers: Optional[dict] = None, tags: Optional[list] = None,
                     regex_priority: int = 0) -> dict:
        route_display = name or str(paths)
        print(f"  Creating route: {route_display} -> service '{service_name_or_id}'")
        payload = {
            "strip_path": strip_path,
            "preserve_host": preserve_host,
            "regex_priority": regex_priority,
        }
        if name:
            payload["name"] = name
        if paths:
            payload["paths"] = paths
        if hosts:
            payload["hosts"] = hosts
        if methods:
            payload["methods"] = methods
        if protocols:
            payload["protocols"] = protocols or ["http", "https"]
        if headers:
            payload["headers"] = headers
        if tags:
            payload["tags"] = tags

        result = self._request("POST", f"/services/{service_name_or_id}/routes", payload)
        print(f"    [OK] Route '{route_display}' created (id: {result.get('id', 'N/A')})")
        return result

    def list_routes(self, service_name_or_id: Optional[str] = None) -> list:
        if service_name_or_id:
            result = self._request("GET", f"/services/{service_name_or_id}/routes")
        else:
            result = self._request("GET", "/routes")
        return result.get("data", [])

    def delete_route(self, route_name_or_id: str) -> dict:
        print(f"Deleting route: {route_name_or_id}")
        return self._request("DELETE", f"/routes/{route_name_or_id}")

    # --- Plugins ---

    def add_plugin(self, plugin_name: str, config: Optional[dict] = None,
                   service_name_or_id: Optional[str] = None,
                   route_name_or_id: Optional[str] = None,
                   consumer_name_or_id: Optional[str] = None,
                   enabled: bool = True, tags: Optional[list] = None) -> dict:
        scope = "global"
        endpoint = "/plugins"

        if service_name_or_id:
            endpoint = f"/services/{service_name_or_id}/plugins"
            scope = f"service '{service_name_or_id}'"
        elif route_name_or_id:
            endpoint = f"/routes/{route_name_or_id}/plugins"
            scope = f"route '{route_name_or_id}'"

        print(f"  Adding plugin '{plugin_name}' ({scope})")
        payload = {
            "name": plugin_name,
            "enabled": enabled,
        }
        if config:
            payload["config"] = config
        if consumer_name_or_id:
            payload["consumer"] = {"id": consumer_name_or_id}
        if tags:
            payload["tags"] = tags

        result = self._request("POST", endpoint, payload)
        print(f"    [OK] Plugin '{plugin_name}' added (id: {result.get('id', 'N/A')})")
        return result

    # --- Consumers ---

    def create_consumer(self, username: str, custom_id: Optional[str] = None,
                        tags: Optional[list] = None) -> dict:
        print(f"Creating consumer: {username}")
        payload = {"username": username}
        if custom_id:
            payload["custom_id"] = custom_id
        if tags:
            payload["tags"] = tags
        result = self._request("POST", "/consumers", payload)
        print(f"  [OK] Consumer '{username}' created (id: {result.get('id', 'N/A')})")
        return result

    def create_consumer_key_auth(self, consumer_name_or_id: str,
                                  key: Optional[str] = None) -> dict:
        print(f"  Creating key-auth for consumer '{consumer_name_or_id}'")
        payload = {}
        if key:
            payload["key"] = key
        result = self._request("POST", f"/consumers/{consumer_name_or_id}/key-auth", payload)
        print(f"    [OK] Key created: {result.get('key', 'N/A')}")
        return result

    # --- Certificates ---

    def add_certificate(self, cert: str, key: str, snis: Optional[list] = None,
                        tags: Optional[list] = None) -> dict:
        print(f"Adding certificate (SNIs: {snis})")
        payload = {
            "cert": cert,
            "key": key,
        }
        if snis:
            payload["snis"] = snis
        if tags:
            payload["tags"] = tags
        result = self._request("POST", "/certificates", payload)
        print(f"  [OK] Certificate added (id: {result.get('id', 'N/A')})")
        return result

    # --- Bulk Configuration ---

    def apply_config(self, config: dict) -> None:
        """Apply a full configuration dictionary containing upstreams, services, routes, and plugins."""
        print("=" * 60)
        print("Starting Kong configuration deployment")
        print("=" * 60)

        # Create upstreams and targets
        for upstream_cfg in config.get("upstreams", []):
            targets = upstream_cfg.pop("targets", [])
            healthchecks = upstream_cfg.pop("healthchecks", None)
            self.create_upstream(
                name=upstream_cfg["name"],
                algorithm=upstream_cfg.get("algorithm", "round-robin"),
                healthchecks=healthchecks,
            )
            for target_cfg in targets:
                self.add_target(
                    upstream_name=upstream_cfg["name"],
                    target=target_cfg["target"],
                    weight=target_cfg.get("weight", 100),
                    tags=target_cfg.get("tags"),
                )

        # Create services
        for service_cfg in config.get("services", []):
            routes = service_cfg.pop("routes", [])
            plugins = service_cfg.pop("plugins", [])
            self.create_service(**service_cfg)

            # Create routes for this service
            for route_cfg in routes:
                route_plugins = route_cfg.pop("plugins", [])
                self.create_route(service_name_or_id=service_cfg["name"], **route_cfg)

                # Add plugins to route
                for plugin_cfg in route_plugins:
                    self.add_plugin(
                        route_name_or_id=route_cfg.get("name"),
                        **plugin_cfg,
                    )

            # Add plugins to service
            for plugin_cfg in plugins:
                self.add_plugin(
                    service_name_or_id=service_cfg["name"],
                    **plugin_cfg,
                )

        # Create consumers
        for consumer_cfg in config.get("consumers", []):
            key_auths = consumer_cfg.pop("key_auths", [])
            self.create_consumer(**consumer_cfg)
            for key_auth in key_auths:
                self.create_consumer_key_auth(
                    consumer_name_or_id=consumer_cfg["username"],
                    key=key_auth.get("key"),
                )

        # Global plugins
        for plugin_cfg in config.get("global_plugins", []):
            self.add_plugin(**plugin_cfg)

        print("=" * 60)
        print("Kong configuration deployment complete!")
        print("=" * 60)

    def print_current_config(self) -> None:
        """Print a summary of the current Kong configuration."""
        print("\n" + "=" * 60)
        print("Current Kong Configuration Summary")
        print("=" * 60)

        services = self.list_services()
        print(f"\nServices ({len(services)}):")
        for svc in services:
            print(f"  - {svc.get('name', 'unnamed')} -> {svc.get('host', 'N/A')}:{svc.get('port', 'N/A')}")
            routes = self.list_routes(svc["id"])
            for route in routes:
                print(f"      Route: {route.get('name', 'unnamed')} "
                      f"paths={route.get('paths')} methods={route.get('methods')} "
                      f"hosts={route.get('hosts')}")

        upstreams = self.list_upstreams()
        print(f"\nUpstreams ({len(upstreams)}):")
        for upstream in upstreams:
            print(f"  - {upstream.get('name')} (algorithm: {upstream.get('algorithm')})")
            targets_resp = self._request("GET", f"/upstreams/{upstream['id']}/targets")
            for target in targets_resp.get("data", []):
                print(f"      Target: {target.get('target')} (weight: {target.get('weight')})")

        plugins_resp = self._request("GET", "/plugins")
        plugins = plugins_resp.get("data", [])
        print(f"\nPlugins ({len(plugins)}):")
        for plugin in plugins:
            scope = "global"
            if plugin.get("service"):
                scope = f"service:{plugin['service'].get('id', 'N/A')}"
            elif plugin.get("route"):
                scope = f"route:{plugin['route'].get('id', 'N/A')}"
            print(f"  - {plugin.get('name')} ({scope}) enabled={plugin.get('enabled')}")

        print("=" * 60)


